function LGpBaseMgr:RegisterTouchEvent(op, touchStartFun, touchMoveFun, touchEndFunc, touchCancelFunc)
	if self._touchOp then
		self:RemoveTouchEvent()
	end
	self._touchOp = op
	if touchStartFun then gLGameTouch:TouchRegister(op,LGameTouch.TOUCH_EVT_START,touchStartFun) end
	if touchMoveFun then gLGameTouch:TouchRegister(op,LGameTouch.TOUCH_EVT_MOVE,touchMoveFun) end
	if touchEndFunc then gLGameTouch:TouchRegister(op,LGameTouch.TOUCH_EVT_END,touchEndFunc) end
	if touchCancelFunc then gLGameTouch:TouchRegister(op,LGameTouch.TOUCH_EVT_CANCEL,touchCancelFunc) end
end

function LGpBaseMgr:UnregisterTouchEvent()
	if gLGameTouch and self._touchOp then
		gLGameTouch:TouchUnRegister(self._touchOp)
		self._touchOp = nil
	end
end

